using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class GreetingTools
{
    [McpServerTool, Description("Returns a personalized greeting message.")]
    public static string Greet(
        [Description("The name of the person to greet")] string name)
    {
        return $"Hello, {name}! Welcome to the MCP HTTP server.";
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(
        UriTemplate = "config://app/settings",
        Name = "App Settings",
        MimeType = "application/json"),
     Description("Returns the current application configuration.")]
    public static string GetAppSettings()
    {
        var config = new
        {
            Version = "1.0.0",
            Environment = "Production",
            Features = new { DarkMode = true, Analytics = false },
            MaxConnections = 100
        };

        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }
}

